// Login page
import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { LogoFull } from '../components/Logo';
import s from './Auth.module.css';

export default function Login() {
  const nav = useNavigate();
  const { login } = useAuth();
  const [form, setForm] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const onChange = e => setForm({ ...form, [e.target.name]: e.target.value });

  const onSubmit = async e => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      await login(form.email, form.password);
      nav('/chat');
    } catch (err) {
      setError(err.response?.data?.detail || 'Email ou mot de passe incorrect.');
    } finally { setLoading(false); }
  };

  return (
    <div className={s.page}>
      <div className={s.bg1} /><div className={s.bg2} />
      <Link to="/" className={s.back}>← Accueil</Link>
      <div className={s.card}>
        <div className={s.cardLogo}><LogoFull size={32} /></div>
        <h1 className={s.title}>Bon retour !</h1>
        <p className={s.sub}>Connectez-vous pour continuer à chatter en Tamazight.</p>
        {error && <div className={s.err}>{error}</div>}
        <form onSubmit={onSubmit} className={s.form}>
          <div className={s.field}>
            <label className={s.label}>Email</label>
            <input className={s.input} type="email" name="email" placeholder="votre@email.com"
              value={form.email} onChange={onChange} required />
          </div>
          <div className={s.field}>
            <label className={s.label}>Mot de passe</label>
            <input className={s.input} type="password" name="password" placeholder="••••••••"
              value={form.password} onChange={onChange} required />
          </div>
          <button className={s.submit} disabled={loading}>
            {loading ? 'Connexion...' : 'Se connecter →'}
          </button>
        </form>
        <p className={s.switch}>Pas encore de compte ? <Link to="/register" className={s.link}>Créer un compte</Link></p>
      </div>
    </div>
  );
}
